    "cases.issue_an_electronic_invoice.step.issue.out.einvoice": "Strukturalna e-faktura",
    "cases.issue_an_electronic_invoice.step.issue.out.sent": "Dostarczona do klienta",
    "cases.issue_an_electronic_invoice.step.issue.title": "Wystaw fakturę elektroniczną",
    "cases.issue_an_electronic_invoice.step.issue.what": "Wygeneruj fakturę jako strukturalny dokument elektroniczny, z numerem referencyjnym nabywcy, szczegółami pozycji i podziałem podatku wymaganymi przez standard, i wyślij ją kanałem, którego wymaga klient.",
    "cases.issue_an_electronic_invoice.step.issue.why": "Coraz więcej krajów i klientów publicznych odrzuca fakturę papierową lub PDF i akceptuje wyłącznie strukturalną e-fakturę. Wystawienie zgodnego formatu sprawia, że faktura jest odczytywana maszynowo i księgowana, zamiast utknąć w kolejce odrzuceń.",
    "cases.issue_an_electronic_invoice.step.track.in.due": "Termin płatności",
    "cases.issue_an_electronic_invoice.step.track.in.invoice": "Wystawiona faktura",
