    "cases.localize_an_estimate_to_a_region.step.apply.out.rerated": "Przeceniony przedmiar",
    "cases.localize_an_estimate_to_a_region.step.apply.title": "Zastosuj lokalne stawki i współczynniki",
    "cases.localize_an_estimate_to_a_region.step.apply.what": "Przecen przedmiar według bazy regionalnej i zastosuj współczynniki korygujące dla lokalizacji i waluty, zachowując ilości bez zmian, tak aby zmieniała się tylko wycena, a zakres pozostał stały.",
    "cases.localize_an_estimate_to_a_region.step.apply.why": "Utrzymanie ilości i zmiana tylko stawek utrzymuje dwa efekty, zakres i cenę, wyraźnie rozdzielone. Dzięki temu widzisz dokładnie, ile z nowej liczby wynika z regionu, a ile z projektu.",
    "cases.localize_an_estimate_to_a_region.step.base.in.estimate": "Wyceniony kosztorys",
    "cases.localize_an_estimate_to_a_region.step.base.in.region": "Docelowy region i waluta",
    "cases.localize_an_estimate_to_a_region.step.base.out.base": "Regionalna baza kosztowa",
    "cases.localize_an_estimate_to_a_region.step.base.out.coverage": "Sprawdzenie pokrycia branżowego",
    "cases.localize_an_estimate_to_a_region.step.base.title": "Wybierz regionalną bazę kosztową",
    "cases.localize_an_estimate_to_a_region.step.base.what": "Wybierz bazę kosztową odpowiadającą regionowi i walucie, w której realizowane będą roboty, i sprawdź, czy obejmuje ona branże z twojego przedmiaru, zamiast pozostawiać luki, które musiałbyś wycenić ręcznie.",
    "cases.localize_an_estimate_to_a_region.step.base.why": "Stawki robocizny, ceny materiałów i wydajność różnią się znacznie między regionami, więc stawka trafna w jednym miejscu może być mocno nietrafiona w innym. Rozpoczęcie od lokalnej bazy utrzymuje kosztorys obronny na nowym rynku.",
    "cases.localize_an_estimate_to_a_region.step.validate.in.benchmarks": "Benchmarki regionalne",
    "cases.localize_an_estimate_to_a_region.step.validate.in.rerated": "Przeceniony przedmiar",
    "cases.localize_an_estimate_to_a_region.step.validate.out.confirmed": "Potwierdzony kosztorys lokalny",
    "cases.localize_an_estimate_to_a_region.step.validate.out.report": "Raport walidacji",
    "cases.localize_an_estimate_to_a_region.step.validate.title": "Zwaliduj zlokalizowaną liczbę",
    "cases.localize_an_estimate_to_a_region.step.validate.what": "Poddaj zlokalizowany kosztorys kontroli pod kątem zerowych cen, pustych ilości i stawek jednostkowych odbiegających od regionalnego przedziału benchmarkowego, i porównaj koszt za metr kwadratowy z lokalnymi budowami.",
    "cases.localize_an_estimate_to_a_region.step.validate.why": "Niedopasowanie waluty lub podwójnie zastosowany współczynnik łatwo ukrywa się w przecenionym przedmiarze i może przesunąć ofertę o poważną wartość. Walidacja względem lokalnych benchmarków wychwytuje pomyłkę, dopóki wciąż można ją dyskretnie poprawić.",
    "cases.localize_an_estimate_to_a_region.title": "Zlokalizuj kosztorys do regionu",
    "cases.maintain_supplier_catalogs_and_buy_from_them.desc": "Importuj i aktualizuj cenniki dostawców, twórz harmonogram zakupów projektu na podstawie tych aktualnych stawek i raportuj wydatki zaangażowane wobec założeń kosztorysu, tak aby nic nie zostało kupione po cichu ponad budżet.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.in.catalogs": "Aktualne katalogi dostawców",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.in.packages": "Zakres pakietu",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.out.orders": "Zaangażowane zamówienia",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.out.schedule": "Wyceniony harmonogram zakupów",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.title": "Utwórz harmonogram zakupów",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.what": "Zbuduj harmonogram zakupów projektu i wyceń każdy pakiet bezpośrednio z aktualnych katalogów dostawców, tak aby każda pozycja niosła rzeczywistą wycenioną stawkę, a nie zgadywane założenie.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.buy.why": "Wycena zakupu na podstawie faktycznego katalogu zamienia grube założenie w zaangażowaną liczbę, do której możesz zobowiązać dostawcę, i oznacza każdą pozycję, w której rynek zmienił się od czasu kosztorysu.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.in.pricelists": "Cenniki dostawców",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.in.updates": "Nowe aktualizacje cen",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.out.catalog": "Aktualne katalogi dostawców",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.out.rates": "Bieżące stawki zakupowe",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.title": "Importuj i aktualizuj katalogi dostawców",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.what": "Zaimportuj każdy cennik dostawcy do własnego katalogu i odświeżaj go za każdym razem, gdy pojawią się nowe ceny, tak aby stawki, wobec których kupujesz, były tymi, które dostawca oferuje dzisiaj.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.why": "Kupowanie na podstawie nieaktualnego cennika to sposób, w jaki pakiet przekracza budżet, zanim jeszcze złożono jedno zamówienie. Aktualny katalog utrzymuje kosztorys i zamówienie pracujące na tych samych liczbach.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.in.allowance": "Założenia kosztorysu",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.in.orders": "Złożone zamówienia",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.out.flags": "Oznaczenia przekroczenia budżetu",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.out.report": "Raport wydatków zaangażowanych",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.title": "Raportuj wydatki zaangażowane wobec założeń",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.what": "Pobierz raport kosztów zaangażowanych i zestaw złożone zamówienia z założeniem zawartym w kosztorysie, pakiet po pakiecie.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.report.why": "Wczesna wiedza o tym, które pakiety kupują ponad swoje założenie, pozwala odzyskać pieniądze gdzie indziej, dopóki jest jeszcze budżet do przesunięcia, a nie dopiero przy rozliczeniu końcowym.",
    "cases.maintain_supplier_catalogs_and_buy_from_them.title": "Utrzymuj katalogi dostawców i kupuj z nich",
    "cases.manage_an_engineering_change.desc": "Przeprowadź zmianę projektową lub inżynierską przez właściwą kontrolę: zgłoś ją z powodem i ryzykiem, wyjaśnij pytania techniczne, które otwiera, w formie zapytań RFI, i przenieś każdy wpływ na koszt lub czas do zlecenia zmiany.",
    "cases.manage_an_engineering_change.step.impact.in.detail": "Potwierdzony szczegół zmiany",
    "cases.manage_an_engineering_change.step.impact.in.pricing": "Wpływ na koszt i czas",
    "cases.manage_an_engineering_change.step.impact.out.agreed": "Uzgodniony koszt i data",
    "cases.manage_an_engineering_change.step.impact.out.order": "Zlecenie zmiany",
    "cases.manage_an_engineering_change.step.impact.title": "Przenieś wpływ do zlecenia zmiany",
    "cases.manage_an_engineering_change.step.impact.what": "Jeśli zmiana wpływa na koszt lub czas, wystaw zlecenie zmiany, które obejmuje wyceniony wpływ i skutek dla harmonogramu, powiązane z zapisem zmiany. Jeśli wpływ jest naprawdę zerowy, zapisz to również.",
    "cases.manage_an_engineering_change.step.impact.why": "Strona inżynierska może zostać zamknięta, a mimo to zostawić pieniądze otwarte. Zlecenie zmiany zamienia zatwierdzoną zmianę w uzgodniony koszt i przesuniętą datę, zanim po cichu stanie się twoim problemem.",
    "cases.manage_an_engineering_change.step.questions.in.questions": "Otwarte pytania techniczne",
