    "cases.model_quality_audit_before_issue.step.classify.title": "Potwierdź kompletność klasyfikacji",
    "cases.model_quality_audit_before_issue.step.classify.what": "Uruchom reguły walidacji i potwierdź, że każdy element ma klasyfikację i zestaw właściwości oczekiwane na następnym etapie, bez pominiętej kategorii.",
    "cases.model_quality_audit_before_issue.step.classify.why": "Model z luką w klasyfikacji przekazuje kolejnemu użytkownikowi, kosztorysantowi lub wykonawcy, element, którego nie może wycenić ani zaplanować bez wcześniejszego pytania do ciebie.",
    "cases.model_quality_audit_before_issue.title": "Skontroluj model przed wydaniem",
    "cases.payment_application_and_reconciliation.desc": "Wyceń pracę wykonaną w tym okresie zgodnie z umową, złóż wniosek o płatność z dowodami, a następnie uzgodnij to, co zostało zatwierdzone, z tym, co faktycznie wpłynęło na konto.",
    "cases.payment_application_and_reconciliation.step.apply.in.materials": "Materiały na budowie",
    "cases.payment_application_and_reconciliation.step.apply.in.sum": "Potwierdzona kwota umowy",
    "cases.payment_application_and_reconciliation.step.apply.in.work": "Praca wykonana w tym cyklu",
    "cases.payment_application_and_reconciliation.step.apply.out.application": "Wniosek o płatność",
    "cases.payment_application_and_reconciliation.step.apply.out.evidence": "Dowody uzupełniające",
    "cases.payment_application_and_reconciliation.step.apply.title": "Złóż wniosek o płatność",
    "cases.payment_application_and_reconciliation.step.apply.what": "Zmierz pracę wykonaną w tym cyklu, dodaj materiały prawidłowo znajdujące się na budowie i zatwierdzone zmiany, a następnie odejmij zatrzymanie i wszystko, co zostało już zapłacone, zanim wystawisz wniosek.",
    "cases.payment_application_and_reconciliation.step.apply.why": "Przepływ gotówki jest tlenem firmy budowlanej, a podwykonawcy odczuwają opóźnione zaświadczenie płatnicze jako pierwsi. Wniosek jasny i w pełni udokumentowany to ten, który zostaje podpisany w terminie.",
    "cases.payment_application_and_reconciliation.step.contract.in.contract": "Podpisana umowa",
    "cases.payment_application_and_reconciliation.step.contract.in.terms": "Zatrzymanie i warunki",
    "cases.payment_application_and_reconciliation.step.contract.in.variations": "Uzgodnione zmiany",
    "cases.payment_application_and_reconciliation.step.contract.out.base": "Aktualna podstawa uprawnienia",
    "cases.payment_application_and_reconciliation.step.contract.out.sum": "Potwierdzona kwota umowy",
    "cases.payment_application_and_reconciliation.step.contract.title": "Potwierdź pozycję umowną",
    "cases.payment_application_and_reconciliation.step.contract.what": "Potwierdź aktualną kwotę umowy, każdą uzgodnioną zmianę oraz warunki zatrzymania i płatności, aby wniosek opierał się na kwocie, na którą obie strony faktycznie się zgodziły.",
    "cases.payment_application_and_reconciliation.step.contract.why": "Wniosek oparty na nieaktualnej liczbie, sprzed wprowadzenia uzgodnionych zmian, wraca natychmiast. Zaczynanie od rzeczywistej pozycji umownej pozwala uzyskać zatwierdzenie bez sporu.",
    "cases.payment_application_and_reconciliation.step.reconcile.in.application": "Wniosek o płatność",
    "cases.payment_application_and_reconciliation.step.reconcile.in.certificate": "Zaświadczenie płatnicze",
    "cases.payment_application_and_reconciliation.step.reconcile.in.remittance": "Otrzymany przelew",
    "cases.payment_application_and_reconciliation.step.reconcile.out.claims": "Roszczenia o niedopłatę",
    "cases.payment_application_and_reconciliation.step.reconcile.out.reconciled": "Uzgodniona pozycja",
    "cases.payment_application_and_reconciliation.step.reconcile.title": "Uzgodnij zatwierdzone z zapłaconym",
    "cases.payment_application_and_reconciliation.step.reconcile.what": "Zestaw to, o co wnioskowałeś, z tym, co dopuścił certyfikujący, i z tym, co faktycznie zapłacono, a następnie ściągaj każdą niedopłatę, błędnie zatrzymane zatrzymanie lub pominiętą pozycję.",
    "cases.payment_application_and_reconciliation.step.reconcile.why": "Kilka procent ściętych z każdego rozliczenia znika po cichu i samo nie wraca. Uzgadnianie każdego cyklu, dopóki dokumentacja jest jeszcze dostępna, to sposób, w jaki te pieniądze wracają.",
    "cases.payment_application_and_reconciliation.title": "Wniosek o płatność i uzgodnienie",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.desc": "Podziel roboty na strefy, ustal rytm taktu, wyrównaj ekipy, aby go utrzymać, i opublikuj linię równowagi dla branż.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.in.crews": "Ekipy branżowe",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.in.takt": "Czas taktu",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.out.histogram": "Wygładzone piki obciążenia siłą roboczą",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.out.levelled": "Wyrównane ekipy",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.title": "Wyrównaj ekipy do rytmu",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.what": "Dobierz i wyrównaj wielkość ekip tak, aby każda branża mogła zakończyć swoją strefę w ramach czasu taktu, bez piku, którego nie da się obsadzić.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.level-crews.why": "Jeśli jedna ekipa nie utrzymuje rytmu, cały pociąg utyka za nią. Wyrównanie na wczesnym etapie jest tańsze niż ściganie brakującej siły roboczej na budowie.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.publish.in.plan": "Wyrównany plan taktu",
