    "cases.set_up_the_asset_register_for_fm.step.attach.out.linked": "Powiązane dokumenty",
    "cases.set_up_the_asset_register_for_fm.step.attach.out.register": "Kompletny rejestr aktywów",
    "cases.set_up_the_asset_register_for_fm.step.attach.title": "Dołącz instrukcje i gwarancje",
    "cases.set_up_the_asset_register_for_fm.step.attach.what": "Powiąż każde aktywo z jego instrukcją eksploatacji, listą części zamiennych i gwarancją, tak by otwarcie aktywa dawało konserwatorowi wszystko, czego potrzebuje, bez osobnego szukania.",
    "cases.set_up_the_asset_register_for_fm.step.attach.why": "Rejestr z dołączonymi dokumentami zamienia nazwę na liście w działającą kartę. Bez instrukcji i gwarancji pod ręką konserwator wraca do zgadywania, a gwarancję łatwo przegapić.",
    "cases.set_up_the_asset_register_for_fm.step.capture.in.asbuilt": "Dokumentacja powykonawcza",
    "cases.set_up_the_asset_register_for_fm.step.capture.in.equipment": "Zainstalowane urządzenia",
    "cases.set_up_the_asset_register_for_fm.step.capture.out.list": "Otagowana lista aktywów",
    "cases.set_up_the_asset_register_for_fm.step.capture.out.tags": "Tagi aktywów",
    "cases.set_up_the_asset_register_for_fm.step.capture.title": "Zarejestruj zainstalowane aktywa",
    "cases.set_up_the_asset_register_for_fm.step.capture.what": "Wypisz każde konserwowalne aktywo, które faktycznie zostało zainstalowane, jego typ, markę i model, i nadaj każdemu tag, tak by można je było znaleźć i wskazać bez wątpliwości.",
    "cases.set_up_the_asset_register_for_fm.step.capture.why": "Rejestr jest przydatny tylko wtedy, gdy odpowiada budynkowi. Aktywo wymienione podczas budowy, ale nigdy nie zaktualizowane na liście, zostawia operatora konserwującego urządzenie, które nigdy nie zostało zamontowane.",
    "cases.set_up_the_asset_register_for_fm.step.handover.in.register": "Kompletny rejestr aktywów",
    "cases.set_up_the_asset_register_for_fm.step.handover.in.team": "Zespół konserwacji",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.issued": "Wydany rejestr",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.ppm": "Gotowość do konserwacji od pierwszego dnia",
    "cases.set_up_the_asset_register_for_fm.step.handover.out.summary": "Podsumowanie zakresu",
    "cases.set_up_the_asset_register_for_fm.step.handover.title": "Przekaż, by konserwacja mogła ruszyć",
    "cases.set_up_the_asset_register_for_fm.step.handover.what": "Wydaj ukończony rejestr zespołowi konserwacji jako kartę, na której będą pracować, i sporządź podsumowanie tego, co obejmuje, tak by konserwacja planowa mogła ruszyć od razu od pierwszego dnia.",
    "cases.set_up_the_asset_register_for_fm.step.handover.why": "Sensem rejestru jest działający budynek, nie zarchiwizowany dokument. Przekazanie go gotowego do użycia pozwala operatorowi zacząć konserwację planową od pierwszego dnia zamiast odbudowywać listę samodzielnie.",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.assets": "Otagowana lista aktywów",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.layout": "Układ kondygnacji i pomieszczeń",
    "cases.set_up_the_asset_register_for_fm.step.locate.in.specs": "Specyfikacje urządzeń",
